'use strict';

var $TypeError = require('es-errors/type');
var gOPD = require('gopd');

var isObject = require('../helpers/isObject');
var isPropertyKey = require('../helpers/isPropertyKey');

var CreateDataPropertyOrThrow = require('./CreateDataPropertyOrThrow');
var SameValue = require('./SameValue');
var Set = require('./Set');



module.exports = function SetterThatIgnoresPrototypeProperties(thisValue, home, p, v) {
	if (!isObject(home)) {
		throw new $TypeError('Assertion failed: `home` must be an object');
	}
	if (!isPropertyKey(p)) {
		throw new $TypeError('Assertion failed: `p` must be a Property Key');
	}

	if (!isObject(thisValue)) { 
		throw new $TypeError('Assertion failed: `thisValue` must be an Object'); 
	}

	if (SameValue(thisValue, home)) { 
		throw new $TypeError('Throwing here emulates assignment to a non-writable data property on the `home` object in strict mode code'); 
	}

	var desc = gOPD(thisValue, p); 

	if (typeof desc === 'undefined') { 
		CreateDataPropertyOrThrow(thisValue, p, v); 
	} else { 
		Set(thisValue, p, v, true); 
	}
};
